import React, { useState, useEffect } from "react";

function AdminDashboard({ billingDate }) {
  const [dashboardData, setDashboardData] = useState({
    totalSales: 0,
    totalBills: 0,
    occupiedTables: 0,
    vacantTables: 0,
    topSellingItems: [],
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, [billingDate]);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`http://localhost:8000/api/admin/dashboard`);

      if (!response.ok) {
        throw new Error("Failed to fetch dashboard data");
      }

      const data = await response.json();
      setDashboardData(data);
      setError(null);
    } catch (err) {
      console.error("Error fetching dashboard data:", err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="admin-dashboard">
        <h2>Admin Dashboard</h2>
        <div className="loading">Loading dashboard data...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="admin-dashboard">
        <h2>Admin Dashboard</h2>
        <div className="error">Error: {error}</div>
        <button onClick={fetchDashboardData} className="retry-button">
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="admin-dashboard">
      <h2>Admin Dashboard</h2>

      <div className="dashboard-stats">
        <div className="stat-card">
          <h3>Total Sales</h3>
          <div className="stat-value">
            ₹{dashboardData.totalSales.toFixed(2)}
          </div>
        </div>

        <div className="stat-card">
          <h3>Total Bills</h3>
          <div className="stat-value">{dashboardData.totalBills}</div>
        </div>

        <div className="stat-card">
          <h3>Occupied Tables</h3>
          <div className="stat-value">{dashboardData.occupiedTables}</div>
        </div>

        <div className="stat-card">
          <h3>Vacant Tables</h3>
          <div className="stat-value">{dashboardData.vacantTables}</div>
        </div>
      </div>

      <div className="top-items-section">
        <h3>Top Selling Items Today</h3>

        {dashboardData.topSellingItems.length > 0 ? (
          <div className="top-items-list">
            {dashboardData.topSellingItems.map((item, index) => (
              <div key={index} className="top-item">
                <span className="item-name">{item.name}</span>
                <span className="item-quantity">Qty: {item.quantity}</span>
                <span className="item-sales">₹{item.sales.toFixed(2)}</span>
              </div>
            ))}
          </div>
        ) : (
          <div className="no-data">No sales data available for today</div>
        )}
      </div>

      <div className="dashboard-actions">
        <button onClick={fetchDashboardData} className="refresh-button">
          Refresh Data
        </button>

        <button
          onClick={() => window.open(`/reports?date=${billingDate}`, "_blank")}
          className="reports-button"
        >
          View Detailed Reports
        </button>
      </div>

      <div className="admin-note">
        <p>
          Admin dashboard providing real-time overview of restaurant operations.
          Use the navigation tabs above to access detailed reports, shift
          management, and other admin functions.
        </p>
      </div>
    </div>
  );
}

export default AdminDashboard;
